#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char S[N + 1];
        scanf("%s", S);
        long long count = 0;
        for (int i = 0; i < N * K; i++) {
            if (S[i % N] == 'a') {
                for (int j = i + 1; j < N * K; j++) {
                    if (S[j % N] == 'b') {
                        count++;
                    }
                }
            }
        }
        printf("%lld\n", count);
    }
    return 0;
}

