import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            String S = sc.next();
            long count = 0;
            for (int i = 0; i < N * K; i++) {
                if (S.charAt(i % N) == 'a') {
                    for (int j = i + 1; j < N * K; j++) {
                        if (S.charAt(j % N) == 'b') {
                            count++;
                        }
                    }
                }
            }
            System.out.println(count);
        }
    }
}

