    const S = lines[idx++];
    let count = 0;
    for (let j = 0; j < N * K; j++) {
        if (S[j % N] === 'a') {
            for (let k = j + 1; k < N * K; k++) {
                if (S[k % N] === 'b') {
                    count++;
                }
            }
        }
    }
    console.log(count);
}
